CREATE TABLE "Comment"("id" UUID NOT NULL,"organizationId" UUID NOT NULL,"entityType" TEXT NOT NULL,"entityId" UUID NOT NULL,"parentCommentId" UUID,"body" TEXT NOT NULL,"authorId" UUID NOT NULL,"editedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"deletedAt" TIMESTAMP(3),"version" INTEGER NOT NULL DEFAULT 1,CONSTRAINT "Comment_pkey" PRIMARY KEY("id"));
CREATE TABLE "Mention"("id" UUID NOT NULL,"commentId" UUID NOT NULL,"mentionedUserId" UUID,"mentionedDepartmentId" UUID,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "Mention_pkey" PRIMARY KEY("id"),CONSTRAINT "Mention_exactly_one_target_check" CHECK (("mentionedUserId" IS NOT NULL)::int + ("mentionedDepartmentId" IS NOT NULL)::int = 1));
CREATE INDEX "Comment_organizationId_entityType_entityId_parentCommentId__idx" ON "Comment"("organizationId","entityType","entityId","parentCommentId","createdAt");CREATE UNIQUE INDEX "Mention_commentId_mentionedUserId_key" ON "Mention"("commentId","mentionedUserId");CREATE UNIQUE INDEX "Mention_commentId_mentionedDepartmentId_key" ON "Mention"("commentId","mentionedDepartmentId");
ALTER TABLE "Comment" ADD CONSTRAINT "Comment_organizationId_fkey" FOREIGN KEY("organizationId") REFERENCES "Organization"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Comment" ADD CONSTRAINT "Comment_authorId_fkey" FOREIGN KEY("authorId") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Comment" ADD CONSTRAINT "Comment_parentCommentId_fkey" FOREIGN KEY("parentCommentId") REFERENCES "Comment"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "Mention" ADD CONSTRAINT "Mention_commentId_fkey" FOREIGN KEY("commentId") REFERENCES "Comment"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "Mention" ADD CONSTRAINT "Mention_mentionedUserId_fkey" FOREIGN KEY("mentionedUserId") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "Mention" ADD CONSTRAINT "Mention_mentionedDepartmentId_fkey" FOREIGN KEY("mentionedDepartmentId") REFERENCES "Department"("id") ON DELETE SET NULL ON UPDATE CASCADE;
